# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class ModelLoader:
    def __init__(self, model_path: str):
        self.model_path = model_path
        self.model = None
        self.model_hash = None
        
    def _validate_model_path(self, path: str) -> bool:
        """Basic validation to prevent path traversal attacks"""
        try:
            # Resolve path to prevent directory traversal
            resolved_path = Path(path).resolve()
            # Ensure path is within allowed boundaries
            if not str(resolved_path).startswith(str(Path(self.model_path).resolve())):
                return False
            return True
        except Exception:
            return False
            
    def _fetch_latest_model(self) -> Optional[str]:
        """Fetch latest model from cloud storage"""
        try:
            if self.model_path.startswith('s3://'):
                return self._fetch_from_s3()
            else:
                return self._fetch_from_local()
        except Exception as e:
            logger.error(f"Failed to fetch model: {e}")
            return None
            
    def _fetch_from_s3(self) -> Optional[str]:
        """Fetch model from S3"""
        try:
            s3 = boto3.client('s3')
            bucket, key = self.model_path[5:].split('/', 1)
            
            # Get latest version from S3
            response = s3.list_object_versions(Bucket=bucket, Prefix=key)
            
            if not response.get('Versions'):
                return None
                
            # Get latest version
            latest_version = max(response['Versions'], key=lambda x: x['LastModified'])
            version_id = latest_version['VersionId']
            
            # Download model
            model_path = f"/tmp/model_{version_id}.pkl"
            s3.download_file(bucket, key, model_path, ExtraArgs={'VersionId': version_id})
            
            return model_path
        except Exception as e:
            logger.error(f"S3 fetch error: {e}")
            return None
            
    def _fetch_from_local(self) -> Optional[str]:
        """Fetch model from local filesystem"""
        try:
            model_path = Path(self.model_path)
            if not model_path.exists():
                return None
            return str(model_path)
        except Exception as e:
            logger.error(f"Local fetch error: {e}")
            return None
            
    def _load_model(self, model_path: str) -> Optional[object]:
        """Load model from file"""
        try:
            with open(model_path, 'rb') as f:
                model = pickle.load(f)
            return model
        except Exception as e:
            logger.error(f"Model loading error: {e}")
            return None
            
    def _calculate_hash(self, model_path: str) -> str:
        """Calculate model file hash for integrity tracking"""
        try:
            hash_md5 = hashlib.md5()
            with open(model_path, "rb") as f:
                for chunk in iter(lambda: f.read(4096), b""):
                    hash_md5.update(chunk)
            return hash_md5.hexdigest()
        except Exception as e:
            logger.error(f"Hash calculation error: {e}")
            return ""
            
    def load_latest_model(self) -> bool:
        """Load latest model version"""
        try:
            model_path = self._fetch_latest_model()
            if not model_path:
                return False
                
            # Validate path
            if not self._validate_model_path(model_path):
                logger.error("Invalid model path detected")
                return False
                
            # Calculate hash
            model_hash = self._calculate_hash(model_path)
            if not model_hash:
                return False
                
            # Load model
            model = self._load_model(model_path)
            if not model:
                return False
                
            self.model = model
            self.model_hash = model_hash
            logger.info(f"Successfully loaded model with hash: {model_hash}")
            return True
            
        except Exception as e:
            logger.error(f"Model loading failed: {e}")
            return False

